        ["Regulatory Oversight", "High, established", "High, evolving", "Low/Evolving"],
        ["Interoperability", "Complex (SWIFT)", "Potentially high (within consortium)", "High (smart contracts)"],
        ["Innovation Pace", "Slow/Deliberate", "Moderate", "Rapid/Experimental"],
        ["Security Model", "Centralized trust", "Permissioned trust", "Cryptographic trust"]
